import LoginForm from '@/components/LoginForm'
import { getServerSession } from 'next-auth/next'
import { authOptions } from '@/lib/auth'
import { redirect } from 'next/navigation'
import type { Session } from 'next-auth'

export default async function HomePage() {
  const session = await getServerSession(authOptions) as Session | null
  if (session && session.user) {
    redirect('/dashboard')
  }
  return (
    <div className="min-h-screen flex items-stretch bg-linear-to-br from-slate-100 via-blue-50 to-sky-100 relative overflow-hidden">
      <div className="hidden md:flex flex-col justify-center items-start w-1/2 px-12 bg-linear-to-br from-blue-700 to-blue-900 text-white relative z-10 shadow-2xl">
        <div className="mb-10">
          <div className="inline-flex items-center justify-center w-20 h-20 bg-white/20 rounded-3xl shadow-xl mb-6 animate-bounce-slow">
            <span className="text-4xl font-extrabold text-white tracking-tight drop-shadow-lg select-none">DR</span>
          </div>
          <h1 className="text-5xl font-extrabold text-white mb-4 tracking-tight drop-shadow-lg">Data4Research</h1>
          <p className="text-lg font-medium text-blue-100 max-w-lg mb-6 drop-shadow-lg">
            Advanced Patient Management System for Medical Professionals
          </p>
        </div>
        </div>
      <div className="flex flex-1 flex-col items-center justify-center relative z-10 w-full px-4 md:px-0">
        <div className="bg-white/95 backdrop-blur-xl rounded-2xl shadow-xl border border-blue-100 px-7 py-8 md:px-12 md:py-14 transition-all duration-300 flex flex-col items-center w-full max-w-md">
          <div className="text-center mb-6 md:hidden">
            <div className="inline-flex items-center justify-center w-14 h-14 bg-blue-700 rounded-2xl shadow-lg mb-3 animate-bounce-slow">
              <span className="text-2xl font-extrabold text-white tracking-tight drop-shadow-lg select-none">DR</span>
            </div>
            <h1 className="text-2xl font-extrabold text-blue-700 mb-1 tracking-tight">Data4Research</h1>
            <p className="text-slate-600 text-sm font-medium">Sign in to access your dashboard</p>
          </div>
          <LoginForm />
        </div>
        <p className="text-center text-slate-500 text-xs mt-6">
          Secure medical data management system
        </p>
      </div>
      <style>{`
        @keyframes bounce-slow { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-10px); } }
        .animate-bounce-slow { animation: bounce-slow 2.5s infinite cubic-bezier(.68,-0.55,.27,1.55); }
      `}</style>
    </div>
  )
}
